using namespace adsk::core;
using namespace adsk::fusion;

Ptr ui;

extern "C" XI_EXPORT bool run(const char* context)
{
    Ptr app = Application::get();
    if (!app)
        return false;

    ui = app->userInterface();
    if (!ui)
        return false;

    Ptr documents = app->documents();
    if (!documents)
        return false;

    Ptr doc = documents->add(DocumentTypes::FusionDesignDocumentType);
    if (!doc)
        return false;

    Ptr product = app->activeProduct();
    if (!product)
        return false;

    Ptr design = product;
    if (!design)
        return false;

    // Get the root component of the active design
    Ptr rootComp = design->rootComponent();
    if (!rootComp)
        return false;

    // Create sketch
    Ptr sketches = rootComp->sketches();
    if (!sketches)
        return false;
    Ptr xz = rootComp->xZConstructionPlane();
    if (!xz)
        return false;
    Ptr sketch = sketches->add(xz);
    if (!sketch)
        return false;
    Ptr sketchCurves = sketch->sketchCurves();
    if (!sketchCurves)
        return false;
    Ptr sketchCircles = sketchCurves->sketchCircles();
    if (!sketchCircles)
        return false;
    Ptr centerPoint = Point3D::create(0, 0, 0);
    if (!centerPoint)
        return false;
    sketchCircles->addByCenterRadius(centerPoint, 3.0);
    Ptr sketchLines = sketchCurves->sketchLines();
    if (!sketchLines)
        return false;
    Ptr startPoint = Point3D::create(5, 0, 0);
    if (!sketchLines)
        return false;
    Ptr endPoint = Point3D::create(5, 30, 0);
    if (!endPoint)
        return false;
    Ptr sketchLine = sketchLines->addByTwoPoints(startPoint, endPoint);
    if (!sketchLine)
        return false;

    // Get the profile defined by the circle.
    Ptr profs = sketch->profiles();
    if (!profs)
        return false;
    Ptr prof = profs->item(0);
    if (!prof)
        return false;

    // Create an extrusion input
    Ptr features = rootComp->features();
    if (!features)
        return false;
    Ptr extrudes = features->extrudeFeatures();
    if (!extrudes)
        return false;
    Ptr extInput = extrudes->createInput(prof, FeatureOperations::NewBodyFeatureOperation);
    if (!extInput)
        return false;

    // Define that the extent is a distance extent of 5 cm.
    Ptr distance = ValueInput::createByReal(5);
    if (!distance)
        return false;
    extInput->setDistanceExtent(false, distance);

    // Create the extrusion.
    Ptr ext = extrudes->add(extInput);
    if (!ext)
        return false;

    // Get the body created by extrusion
    Ptr bodies = ext->bodies();
    if (!bodies)
        return false;
    Ptr body = bodies->item(0);
    if (!body)
        return false;

    // Create input entities for path pattern
    Ptr inputEntites = ObjectCollection::create();
    if (!inputEntites)
        return false;
    inputEntites->add(body);

    // Create path for path pattern
    Ptr path = features->createPath(sketchLine);
    if (!path)
        return false;

    // Quantity and distance
    Ptr quantity = ValueInput::createByString("3");
    if (!quantity)
        return false;
    Ptr patternDistance = ValueInput::createByString("8 cm");
    if (!patternDistance)
        return false;

    // Create the input for path pattern
    Ptr pathPatterns = features->pathPatternFeatures();
    if (!pathPatterns)
        return false;
    Ptr pathPatternInput = pathPatterns->createInput(
        inputEntites, path, quantity, patternDistance, PatternDistanceType::SpacingPatternDistanceType);
    if (!pathPatternInput)
        return false;

    // Create the path pattern
    Ptr pathFeature = pathPatterns->add(pathPatternInput);
    if (!pathFeature)
        return false;

    return true;
}
